(change in A / change in l / change in T₁ / change in T₂)", "options": [{"label": "A", "text": "doubles / no change / no change / no change"}, {"label": "B", "text": "halves / no change / no change / no change"}, {"label": "C", "text": "no change / doubles / no change / no change"}, {"label": "D", "text": "no change / halves / no change / no change"}, {"label": "E", "text": "no change / no change / decreases by 10 °C / increases by 10 °C"}, {"label": "F", "text": "no change / no change / decreases by 10 °C / no change"}, {"label": "G", "text": "no change / no change / increases by 10 °C / decreases by 10 °C"}, {"label": "H", "text": "no change / no change / increases by 10 °C / increases by 10 °C"}], "figures": []}, "generation": {"template_id": "physics_q021", "template_version": "1.0", "parameters": {}, "solution_steps": [], "distractor_strategy": []}, "validation": {"answer_label": "H", "answer_text": "no change / no change / increases by 10 °C / increases by 10 °C", "status": "verified"}, "metadata": {"estimated_time_seconds": null, "tags": ["physics"]}, "data_quality_notes": []}

