(lose by convection) / (greatest emission rate)", "options": [{"label": "A", "text": "P and Q / P"}, {"label": "B", "text": "P and Q / Q"}, {"label": "C", "text": "P and Q / R"}, {"label": "D", "text": "P and Q / S"}, {"label": "E", "text": "R and S / P"}, {"label": "F", "text": "R and S / Q"}, {"label": "G", "text": "R and S / R"}, {"label": "H", "text": "R and S / S"}], "figures": [{"figure_id": "q31_balls", "type": "figure", "src": "images_2016/q31_balls.png"}]}, "generation": {"template_id": "physics_q031", "template_version": "1.0", "parameters": {}, "solution_steps": [], "distractor_strategy": []}, "validation": {"answer_label": "D", "answer_text": "P and Q / S", "status": "verified"}, "metadata": {"estimated_time_seconds": null, "tags": ["physics"]}, "data_quality_notes": []}

